#include<stdio.h>
int main(){
    int n=1,k,c=0;
    scanf("%d",&k);
    while(n<=1000000000){
        int s=0;
        int num=n;
        while(num!=0){
        int  r = num % 10;
        s= s+r;
        num = num/10;
        }
        n++;
        if(s==10)
        {
            c++;
        }
        if(c==k){
            printf("%d",n-1);
            break;
        }
    }

}

